func solve(weight []int64) int64 {
	n := len(weight)
	if n == 0 {
		return 0
	}

	// Use a max-heap to keep track of the maximum weight in the current window
	maxHeap := make([]int64, 0)
	// We'll also track the start and end indices of the current window
	start := 0
	result := 0

	for end := 0; end < n; end++ {
		// Add the current weight to the heap
		heap.Push(&maxHeap, weight[end])

		// Check if the current window is a balanced shipment
		if weight[end] < maxHeap[0] {
			// If it is, increment the result and reset the window
			result++
			start = end + 1
			maxHeap = maxHeap[:0]
		} else {
			// If not, continue expanding the window
			continue
		}
	}

	return int64(result)
}

