func solve(weight []int64) int64 {
	n := len(weight)
	if n < 2 {
		return 0
	}

	// We will use a greedy approach with a sliding window and a max-heap to track the maximum weight in the current window.
	// We maintain a window [left, right], and for each right, we check if the current window is a balanced shipment.
	// If it is, we take it and move left to right + 1.
	// Otherwise, we expand the window to the right.

	left := 0
	result := 0
	maxHeap := make([]int64, 0)

	for right := 0; right < n; right++ {
		// Add current weight to the max-heap
		heap.Push(&maxHeap, weight[right])

		// Check if the current window is a balanced shipment
		// A balanced shipment requires that the last element is strictly less than the maximum in the window
		if weight[right] < maxHeap[0] {
			result++
			// Move left to right + 1, and reset the heap
			left = right + 1
			maxHeap = make([]int64, 0)
		} else {
			// Remove elements from the heap that are out of the current window
			for len(maxHeap) > 0 && maxHeap[0] == weight[left] {
				heap.Pop(&maxHeap)
				left++
			}
		}
	}

	return int64(result)
}
